import{_ as s,o as a,c as n,a4 as i}from"./chunks/framework.CtnSHCpE.js";const h=JSON.parse('{"title":"Common Issues and their solutions","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/CommonSolutions.md","filePath":"Guides/CommonSolutions.md","lastUpdated":1726858945000}'),t={name:"Guides/CommonSolutions.md"};function l(p,e,o,r,c,d){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="common-issues-and-their-solutions" tabindex="-1">Common Issues and their solutions <a class="header-anchor" href="#common-issues-and-their-solutions" aria-label="Permalink to &quot;Common Issues and their solutions&quot;">​</a></h1><h2 id="c-pipe-c-open-do-not-tag-newly-created-file-descriptors" tabindex="-1">C pipe, C open do not tag newly created file descriptors <a class="header-anchor" href="#c-pipe-c-open-do-not-tag-newly-created-file-descriptors" aria-label="Permalink to &quot;C pipe, C open do not tag newly created file descriptors&quot;">​</a></h2><p>Note: in most cases you can use the zoslibport package for ASCII/EBCDIC issues. See <a href="https://github.com/zopencommunity/zoslibport" target="_blank" rel="noreferrer">zoslib</a> for details.</p><p>A common problem when porting code to z/OS and building with ASCII is that when files are created, the contents are written out in ASCII but by default the files are not tagged to indicate the content is in ASCII. Subsequently, other tools have to <em>guess</em> what codepage the contents are in, and often the tools <em>guess</em> EBCDIC. There are many ways that people describe an encoding:</p><ul><li>ASCII, EBCDIC, Single-byte, Double-byte, Multi-byte are fairly generic terms. When people refer to an ASCII encoding, it represents a small number of the complete 256 single-byte character mappings, and typically refers to one of the ISO8859 code pages. The same is true when people refer to an EBCDIC encoding. There are a small number of the complete single-byte character mappings that are constant across the EBCDIC code pages.</li><li>When specifying an ASCII or EBCDIC format, the more precise <em>coded character set identifier</em> (CCSID) is used. We code to CCSID <em>ISO8859-1</em>, also known as <em>819</em>, because z/OS is optimized for this particular ASCII CCSID, and it is consistent with what people on other platforms equate to <em>ASCII</em>.</li></ul><p>The following C code tags a file when it is opened for write as 819 (ISO8859-1):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fd = open(...); /* open new file for WRITE */</span></span>
<span class="line"><span>if (fd &lt; 0) { ... } /* unable to open file */</span></span>
<span class="line"><span>#ifdef __MVS__</span></span>
<span class="line"><span>  #if (__CHARSET_LIB ==	1)</span></span>
<span class="line"><span>    setccsid(fd, 819);</span></span>
<span class="line"><span>  #endif</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>You can also tag a file as 819 using the shell as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chtag -tc819 &lt;file&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>or alternately:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chtag -tcISO8859-1 &lt;file&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The z/OS specific code needs to be double-protected. The <code>#ifdef __MVS__</code> ensures that this is specific to z/OS. The <code>#if (__CHARSET_LIB == 1)</code> ensures that this code is only active when being built with <code>-qascii</code>, so that if others want to build with EBCDIC, they won&#39;t get this behaviour. The function <code>setccsid</code> is also required. This can be either a static function if all the calls to setccsid are in one file, or an external function. Here is a simple version - you may need something more complex if you want to check how the file is opened first (e.g. to prevent setting the CCSID if the file is being opened for READ):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#ifdef __MVS__</span></span>
<span class="line"><span> #if (__CHARSET_LIB == 1)</span></span>
<span class="line"><span>#   include &lt;stdio.h&gt;</span></span>
<span class="line"><span>#   include &lt;stdlib.h&gt;</span></span>
<span class="line"><span> </span></span>
<span class="line"><span>    static int setccsid(int fd, int ccsid)</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      attrib_t attr;</span></span>
<span class="line"><span>      int rc;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      memset(&amp;attr, 0, sizeof(attr));</span></span>
<span class="line"><span>      attr.att_filetagchg = 1;</span></span>
<span class="line"><span>      attr.att_filetag.ft_ccsid = ccsid;</span></span>
<span class="line"><span>      attr.att_filetag.ft_txtflag = 1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      rc = __fchattr(fd, &amp;attr, sizeof(attr));</span></span>
<span class="line"><span>      return rc;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  #endif</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p>Further reading:</p><ul><li><a href="https://www.ibm.com/docs/en/zos/latest?topic=descriptions-chtag-change-file-tag-information" target="_blank" rel="noreferrer">chtag - Change file tag information</a></li><li><a href="https://makingdeveloperslivesbetter.wordpress.com/2022/01/07/is-z-os-ascii-or-ebcdic-yes/" target="_blank" rel="noreferrer">ASCII and EBCDIC on z/OS</a></li><li><a href="https://www.ibm.com/docs/en/ztpf/latest?topic=support-character-sets" target="_blank" rel="noreferrer">Character sets</a></li><li><a href="https://en.wikipedia.org/wiki/CCSID" target="_blank" rel="noreferrer">CCSID</a></li><li><a href="https://en.wikipedia.org/wiki/ISO/IEC_8859-1" target="_blank" rel="noreferrer">ASCII 8859-1</a></li></ul><h2 id="fsum7327-signal-number-xx-not-conventional" tabindex="-1">FSUM7327 signal number XX not conventional <a class="header-anchor" href="#fsum7327-signal-number-xx-not-conventional" aria-label="Permalink to &quot;FSUM7327 signal number XX not conventional&quot;">​</a></h2><p>Note: If you are seeing this error in a source file from gnulib tools package, a fix for this has been <a href="https://git.savannah.gnu.org/gitweb/?p=gnulib.git;a=commit;h=835b3ea801782fcf72ef1f9397bb112cac0e2f50" target="_blank" rel="noreferrer">upstreamed</a> on November 26, 2022 and so the &#39;fix&#39; is probably to get the software package to pick up a new version of gnulib tools.</p><p>See: <a href="https://tech.mikefulton.ca/FSUM7327" target="_blank" rel="noreferrer">FSUM7327</a> which is relatively cryptic and <a href="https://tech.mikefulton.ca/POSIXSignalNumbers" target="_blank" rel="noreferrer">kill</a>.</p><p>Only <em>some</em> signals have a well-defined number that can be used when specifying an action (such as kill or trap). In particular, signal number 13 (which is PIPE) is <em>not</em> a well-defined signal number. As such, code that specifies signal 13 gets the cryptic error message above and can be re-coded to use PIPE instead (see signal.h if the signal number in question isn&#39;t 13, in which case you will need to see what a Linux signal XX is and then re-code it with a name. Note that you need to drop the <em>SIG</em> part at the start of the name to be conformant).</p><p>Here is a common code sequence you might see in a shell script for testing or configuring:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>do_exit=&#39;rm -f $log_file $trs_file; (exit $st); exit $st&#39;</span></span>
<span class="line"><span>trap &quot;st=129; $do_exit&quot; 1</span></span>
<span class="line"><span>trap &quot;st=130; $do_exit&quot; 2</span></span>
<span class="line"><span>trap &quot;st=141; $do_exit&quot; 13</span></span>
<span class="line"><span>trap &quot;st=143; $do_exit&quot; 15</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>The trap lines might vary as might the variables and exit codes. The thing to change, which is <em>no less portable than the 13, but not required to work</em>, is to instead say:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>do_exit=&#39;rm -f $log_file $trs_file; (exit $st); exit $st&#39;</span></span>
<span class="line"><span>trap &quot;st=129; $do_exit&quot; 1</span></span>
<span class="line"><span>trap &quot;st=130; $do_exit&quot; 2</span></span>
<span class="line"><span>trap &quot;st=141; $do_exit&quot; PIPE</span></span>
<span class="line"><span>trap &quot;st=143; $do_exit&quot; 15</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>For Linux, the signal numbers can be found under <a href="https://www.man7.org/linux/man-pages/man7/signal.7.html" target="_blank" rel="noreferrer">signal(7)</a>. For POSIX, a number of signals (but not SIGPIPE) have well-defined names: <a href="https://www.unix.com/man-page/POSIX/1posix/trap/" target="_blank" rel="noreferrer">POSIX trap</a>. For Linux, here is a similar doc: <a href="https://www.man7.org/linux/man-pages/man1/trap.1p.html" target="_blank" rel="noreferrer">Linux trap</a>. Note that <em>HUP</em> is a POSIX supported name, but <em>SIGHUP</em> might also work. Also note that neither <em>PIPE</em> nor 13 is officially supported...</p><p>This will make z/OS happy and is arguably more clear. Ideally, you could change the other trap values as well to use their names, e.g.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>do_exit=&#39;rm -f $log_file $trs_file; (exit $st); exit $st&#39;</span></span>
<span class="line"><span>trap &quot;st=129; $do_exit&quot; HUP</span></span>
<span class="line"><span>trap &quot;st=130; $do_exit&quot; INT</span></span>
<span class="line"><span>trap &quot;st=141; $do_exit&quot; PIPE</span></span>
<span class="line"><span>trap &quot;st=143; $do_exit&quot; TERM</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>On z/OS, you can find these values in <code>/usr/include/le/signals.h</code></p><h2 id="cee3728s-the-use-of-a-function-which-is-not-supported-by-this-release-of-language-environment-was-detected" tabindex="-1">CEE3728S The use of a function, which is not supported by this release of Language Environment was detected. <a class="header-anchor" href="#cee3728s-the-use-of-a-function-which-is-not-supported-by-this-release-of-language-environment-was-detected" aria-label="Permalink to &quot;CEE3728S The use of a function, which is not supported by this release of Language Environment was detected.&quot;">​</a></h2><p>LE provides stubs for some functions that are not yet implemented. This means that they exist in the DLL and side deck, but if you call them they just put out the CEE3728S error message. This causes a problem for builds which detect the available functions on the target OS and conditionally include source based on the detected functions. Since these stub functions are detected, the built component will try to use them.</p><p>The issue can be addressed with a workaround which removes the stub functions from the side deck so that the builds fail to detect them. Changing the side deck in the system library is not advisable, so the following steps allow a copy to be used.</p><ul><li>Clone the <a href="https://github.com/MikeFultonDev/sbin" target="_blank" rel="noreferrer">https://github.com/MikeFultonDev/sbin</a> repository to your z/OS system.</li><li>Run the rmceertfm script to produce an edited side deck in /tmp.</li><li>Take your own copy of the CEE.SCEELIB dataset with all members.</li><li>Replace the CELQS003 member with the modified version created by rmceertfm.</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cp /tmp/celqs003.x &quot;//&#39;FRED.ZOPEN.ZOS204.SCEELIB(CELQS003)&#39;&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Take your own copy of the xlclang configuration file.</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cp /usr/lpp/cbclib/xlclang/etc/xlclang.cfg /u/fred/xlclang.cfg.zos204.noceertfm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Edit the copy of the config file, updating exportlist_c_64 and exportlist_cpp_64 to point to the modified SCEELIB dataset.</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              exportlist_c_64   = fred.zopen.zos204.sceelib(celqs003)</span></span>
<span class="line"><span>              exportlist_cpp_64 = fred.zopen.zos204.sceelib(celqs003,celqscpp,cxxrt64)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>Tell the compiler to use the modified config file.</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export CLC_CONFIG=/u/fred/xlclang.cfg.zos204.noceertfm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="s-typeisshm-macro-gives-an-error-when-compiled" tabindex="-1">S_TYPEISSHM macro gives an error when compiled <a class="header-anchor" href="#s-typeisshm-macro-gives-an-error-when-compiled" aria-label="Permalink to &quot;S_TYPEISSHM macro gives an error when compiled&quot;">​</a></h2><p>The error might be something like: <code>called object type &#39;int&#39; is not a function or function pointer</code></p><p>This is due to a bug in the LE header file <code>sys/modes.h</code> which defines the macros as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       #ifdef __SUSV3_POSIX                                  /*#5@D1A*/</span></span>
<span class="line"><span>         #define S_TYPEISMQ  (0)         /* Test for a message queue */</span></span>
<span class="line"><span>         #define S_TYPEISSEM (0)         /* Test for a semaphore     */</span></span>
<span class="line"><span>         #define S_TYPEISSHM (0)         /* Test for a shared memory */</span></span>
<span class="line"><span>                                         /* object                   */</span></span>
<span class="line"><span>       #endif /* __SUSV3_POSIX */</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>This is unfortunately wrong because the macro expects a parameter to be passed to it (the z/OS team has been notified and hopefully a fix will be provided soon).</p><p>The simplest workaround is to provide a patch to the open source package. <code>findutils</code> currently has a patch for this:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+#ifdef __MVS__</span></span>
<span class="line"><span>+  /* z/OS incorrectly defined these macros - if they are present,</span></span>
<span class="line"><span>+   * redefined them</span></span>
<span class="line"><span>+   */</span></span>
<span class="line"><span>+  #ifdef S_TYPEISSEM</span></span>
<span class="line"><span>+     #undef S_TYPEISSEM</span></span>
<span class="line"><span>+     #define S_TYPEISSEM(x) (0)</span></span>
<span class="line"><span>+  #endif</span></span>
<span class="line"><span>+  #ifdef S_TYPEISMQ</span></span>
<span class="line"><span>+     #undef S_TYPEISMQ</span></span>
<span class="line"><span>+     #define S_TYPEISMQ(x) (0)</span></span>
<span class="line"><span>+  #endif</span></span>
<span class="line"><span>+  #ifdef S_TYPEISSHM</span></span>
<span class="line"><span>+     #undef S_TYPEISSHM</span></span>
<span class="line"><span>+     #define S_TYPEISSHM(x) (0)</span></span>
<span class="line"><span>+  #endif</span></span>
<span class="line"><span>+  #ifdef S_TYPEISTMO</span></span>
<span class="line"><span>+     #undef S_TYPEISTMO</span></span>
<span class="line"><span>+     #define S_TYPEISTMO(x) (0)</span></span>
<span class="line"><span>+  #endif</span></span>
<span class="line"><span>+#endif</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h1 id="libtool-complains-that-passing-o-object-files-as-libraries-is-not-allowed" tabindex="-1">Libtool complains that passing .o object files as libraries is not allowed <a class="header-anchor" href="#libtool-complains-that-passing-o-object-files-as-libraries-is-not-allowed" aria-label="Permalink to &quot;Libtool complains that passing .o object files as libraries is not allowed&quot;">​</a></h1><p>By default, projects that use libtool during the build phase will complain about the use of .o files as libraries when they are passed in via the LIBS variable. Here&#39;s an example of the error message:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>libtool:   error: cannot build libtool library &#39;liblzma.la&#39; from non-libtool objects on this host: /home/itodoro/zopen-data/prod/zoslib-autocvt_tty/lib/celquopt.s.o</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>When zoslib is included as a dependency, it automatically adds .o files to the <code>ZOPEN_EXTRA_LIBS</code> environment variable, which will eventually be passed as the LIBS variable.</p><p>To override this, you can modify the configure script as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+openedition)</span></span>
<span class="line"><span>+  lt_cv_deplibs_check_method=pass_all</span></span>
<span class="line"><span>+  ;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Here&#39;s an example pull request that was done for man-db: <a href="https://github.com/zopencommunity/man-dbport/pull/23/files" target="_blank" rel="noreferrer">https://github.com/zopencommunity/man-dbport/pull/23/files</a></p><h1 id="displaying-compile-commands-in-the-build-output" tabindex="-1">Displaying compile commands in the build output <a class="header-anchor" href="#displaying-compile-commands-in-the-build-output" aria-label="Permalink to &quot;Displaying compile commands in the build output&quot;">​</a></h1><p>When building projects, it can be helpful to see the actual compile commands being executed. This can aid in understanding the build process, diagnosing issues, or debugging. The zopen build tool provides an option, -vv, for very verbose output. By using this option with the zopen build command, you can enable the display of the compile commands.</p><p>Internally, zopen sets the <code>V</code> and <code>VERBOSE</code> environment variables to 1 when the -vv option is specified. GNU Make, and other build systems, respect these variables and display the executed commands during the build process.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen build -vv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h1 id="some-of-the-text-colors-are-too-bright-for-my-terminal-s-background" tabindex="-1">Some of the text colors are too bright for my terminal&#39;s background <a class="header-anchor" href="#some-of-the-text-colors-are-too-bright-for-my-terminal-s-background" aria-label="Permalink to &quot;Some of the text colors are too bright for my terminal&#39;s background&quot;">​</a></h1><p>If your background is a lighter color, the header or warning colors could be almost impossible to read as they are by default yellow. There exists a variable in bash that if you change it, it will update the color scheme. The following <strong>bash</strong> command is for changing the color scheme to fit a light terminal background.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COLORFGBG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0;15&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,59)])])}const b=s(t,[["render",l]]);export{h as __pageData,b as default};
